import React, { useEffect, useRef } from 'react';
import profileImage from '../assets/profile.png';
import '../styles/components/About.css';

const About = () => {
  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = React.useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => {
      if (sectionRef.current) {
        observer.unobserve(sectionRef.current);
      }
    };
  }, []);

  return (
    <section id="about" className="about section" ref={sectionRef}>
      <div className="container">
        <h2 className="section-title">About Me</h2>
        <div className={`about-content ${isVisible ? 'visible' : ''}`}>
          <div className="about-image-wrapper">
            <div className="image-border"></div>
            <img 
              src={profileImage} 
              alt="Aarav Sahni in aircraft cockpit" 
              className="about-image"
            />
            <div className="image-glow"></div>
          </div>
          <div className="about-text">
            <h3>Passionate Developer & Aviation Enthusiast</h3>
            <p>
              Hi, I'm Aarav Sahni. I'm a developer who combines my passion for technology 
              with my love for aviation. I specialize in building modern web applications, 
              managing self-hosted infrastructure, and creating innovative solutions.
            </p>
            <p>
              When I'm not coding, you'll find me exploring the world of aviation, whether 
              it's learning about aircraft systems, managing game servers, or building 
              infrastructure that powers my projects.
            </p>
            <p>
              I'm passionate about self-hosting, which has led me to set up comprehensive 
              infrastructure including game servers, VPNs, ad-blocking, Discord bots, and 
              reverse proxies. I believe in understanding the full stack, from frontend 
              interfaces to backend infrastructure.
            </p>
            <div className="about-highlights">
              <div className="highlight-item">
                <span className="highlight-icon">🚀</span>
                <div>
                  <h4>Full-Stack Development</h4>
                  <p>Building end-to-end solutions</p>
                </div>
              </div>
              <div className="highlight-item">
                <span className="highlight-icon">🛠️</span>
                <div>
                  <h4>Infrastructure & DevOps</h4>
                  <p>Self-hosted solutions & automation</p>
                </div>
              </div>
              <div className="highlight-item">
                <span className="highlight-icon">✈️</span>
                <div>
                  <h4>Aviation Technology</h4>
                  <p>Bridging tech and aviation</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;
